import logging
import time

logger = logging.getLogger("llm_service.inference")

def generate(prompt: str, model: str, request_id: str) -> str:
    start = time.perf_counter()
    logger.info("Generation started", extra={"request_id": request_id, "model": model, "prompt_len": len(prompt)})

    try:
        response = call_llm_api(model=model, prompt=prompt)
        latency_ms = (time.perf_counter() - start) * 1000
        logger.info(
            "Generation complete",
            extra={
                "request_id": request_id,
                "model": model,
                "latency_ms": round(latency_ms, 2),
                "output_tokens": response.usage.completion_tokens,
            }
        )
        return response.choices[0].message.content

    except RateLimitError:
        logger.warning("Rate limit hit", extra={"request_id": request_id, "model": model})
        raise
    except Exception:
        logger.exception("Unexpected generation error", extra={"request_id": request_id})
        raise

